-- SQL Script to import lipstick data
-- Generated automatically by scrape.py

CREATE TABLE IF NOT EXISTS lipsticks (
    id INT PRIMARY KEY,
    brand VARCHAR(100),
    product_name VARCHAR(255),
    shade_name VARCHAR(100),
    hex_code VARCHAR(10),
    rgb_r INT,
    rgb_g INT,
    rgb_b INT,
    hsl_h INT,
    hsl_s INT,
    hsl_l INT,
    lab_l DECIMAL(5,2),
    lab_a DECIMAL(5,2),
    lab_b DECIMAL(5,2),
    color_family VARCHAR(100),
    price_tier VARCHAR(50),
    image_base64 LONGTEXT,
    original_image_url VARCHAR(500),
    dupes_json TEXT
);

TRUNCATE TABLE lipsticks;

